import React, { createContext, useState, useContext, useEffect } from 'react';

const InventoryContext = createContext();

export const useInventory = () => {
  const context = useContext(InventoryContext);
  if (!context) {
    throw new Error('useInventory must be used within an InventoryProvider');
  }
  return context;
};

export const InventoryProvider = ({ children }) => {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const storedItems = localStorage.getItem('inventoryItems');
    if (storedItems) {
      setItems(JSON.parse(storedItems));
    } else {
      const sampleItems = [
        {
          id: '1',
          name: 'Laptop Dell XPS 15',
          sku: 'LP-DEL-001',
          quantity: 15,
          price: 1299.99,
          category: 'Electronics',
          description: 'High-performance laptop with 15.6" display, Intel i7 processor, 16GB RAM, 512GB SSD',
          image: 'https://images.unsplash.com/photo-1496181133206-80ce9b88a853?w=300',
          availability: true,
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        },
        {
          id: '2',
          name: 'Office Chair Ergonomic',
          sku: 'CHR-ERG-002',
          quantity: 8,
          price: 349.99,
          category: 'Furniture',
          description: 'Ergonomic office chair with lumbar support, adjustable height, and breathable mesh back',
          image: 'https://images.unsplash.com/photo-1586023492125-27b2c045efd7?w=300',
          availability: true,
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        },
        {
          id: '3',
          name: 'Wireless Mouse Logitech',
          sku: 'MOU-LOG-003',
          quantity: 0,
          price: 29.99,
          category: 'Electronics',
          description: 'Ergonomic wireless mouse with precision tracking, long battery life',
          image: 'https://images.unsplash.com/photo-1527864550417-7fd91fc51a46?w=300',
          availability: false,
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        }
      ];
      setItems(sampleItems);
      localStorage.setItem('inventoryItems', JSON.stringify(sampleItems));
    }
    setLoading(false);
  }, []);

  const addItem = (itemData) => {
    const newItem = {
      id: Date.now().toString(),
      ...itemData,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };

    const updatedItems = [...items, newItem];
    setItems(updatedItems);
    localStorage.setItem('inventoryItems', JSON.stringify(updatedItems));

    return { success: true, item: newItem };
  };

  const updateItem = (id, itemData) => {
    const updatedItems = items.map(item => 
      item.id === id 
        ? { ...item, ...itemData, updatedAt: new Date().toISOString() }
        : item
    );

    setItems(updatedItems);
    localStorage.setItem('inventoryItems', JSON.stringify(updatedItems));

    return { success: true, item: updatedItems.find(item => item.id === id) };
  };

  const deleteItem = (id) => {
    const updatedItems = items.filter(item => item.id !== id);
    setItems(updatedItems);
    localStorage.setItem('inventoryItems', JSON.stringify(updatedItems));

    return { success: true };
  };

  const getItem = (id) => {
    return items.find(item => item.id === id);
  };

  const searchItems = (query) => {
    if (!query) return items;

    const lowercaseQuery = query.toLowerCase();
    return items.filter(item => 
      item.name.toLowerCase().includes(lowercaseQuery) ||
      item.sku.toLowerCase().includes(lowercaseQuery) ||
      item.category.toLowerCase().includes(lowercaseQuery) ||
      item.description.toLowerCase().includes(lowercaseQuery)
    );
  };

  const filterByCategory = (category) => {
    if (!category || category === 'all') return items;
    return items.filter(item => item.category === category);
  };

  const getCategories = () => {
    return [...new Set(items.map(item => item.category))];
  };

  const getStats = () => {
    const totalItems = items.length;
    const totalQuantity = items.reduce((sum, item) => sum + item.quantity, 0);
    const availableItems = items.filter(item => item.availability).length;
    const outOfStock = items.filter(item => item.quantity === 0).length;
    const totalValue = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);

    return {
      totalItems,
      totalQuantity,
      availableItems,
      outOfStock,
      totalValue
    };
  };

  const value = {
    items,
    loading,
    addItem,
    updateItem,
    deleteItem,
    getItem,
    searchItems,
    filterByCategory,
    getCategories,
    getStats
  };

  return (
    <InventoryContext.Provider value={value}>
      {children}
    </InventoryContext.Provider>
  );
};
